1	package routing
2	
3	// costClassRank maps cost class to numeric rank (lower = cheaper).
4	var costClassRank = map[string]int{
5		"local":        0,
6		"cheap":        1,
7		"medium":       2,
8		"expensive":    3,
9		"experimental": -1,
10		"":             2, // unknown = medium
11	}
12	
13	const StickyAffinityBonus = 250.0
14	const unknownUtilizationPenalty = 5.0
15	const unknownPerformancePenalty = 5.0
16	const belowMinPowerPenalty = 12.0
17	
18	// scorePolicy returns a score for a candidate under the named policy.
19	// Higher is better.
20	//
21	// Routing priority policy (ported from DDx routing.go):
22	//   - cheap: local + low-cost preferred; subscription-within-quota next.
23	//   - default: balanced; light local/subscription preference to avoid spend.
24	//   - smart: quality first; cloud capability wins; no local bonus.
25	//
26	// The policy is policy-aware AND provider-aware via providerBias hooks
27	// supplied by the caller (cooldown demotion, observation perf bias,
28	// provider-affinity bias).
29	func scorePolicy(policy string, cand candidateInternal) float64 {
30		total := 0.0
31		for _, component := range scoreComponents(policy, cand) {
32			total += component
33		}
34		return total
35	}
36	
37	func scoreComponents(policy string, cand candidateInternal) map[string]float64 {
38		components := map[string]float64{
39			"base":                100,
40			"cost":                0,
41			"deployment_locality": 0,
42			"quota_health":        0,
43			"utilization":         0,
44			"performance":         0,
45			"power":               0,
46			"context_headroom":    0,
47			"sticky_affinity":     0,
48		}
49		base := 100.0
50		cr := costClassRank[cand.CostClass]
51		withinQuota := cand.IsSubscription && cand.QuotaOK
52		hasPowerBounds := cand.MinPower > 0 || cand.MaxPower > 0
53		add := func(name string, value float64) {
54			if value == 0 {
55				return
56			}
57			components[name] += value
58		}
59	
60		if !hasPowerBounds {
61			switch policy {
62			case "cheap":
63				if cand.CostClass == "local" {
64					base += 40
65					add("deployment_locality", 40)
66				} else if withinQuota {
67					base += 20
68					add("quota_health", 20)
69				}
70				base -= float64(cr) * 30
71				add("cost", -float64(cr)*30)
72	
73			case "default":
74				if cand.CostClass == "local" {
75					base += 25
76					add("deployment_locality", 25)
77				} else if withinQuota {
78					base += 15
79					add("quota_health", 15)
80				}
81				base -= float64(cr) * 10
82				add("cost", -float64(cr)*10)
83	
84			case "smart":
85				// Quality first; higher cost rank approximates higher capability.
86				base += float64(cr) * 20
87				add("cost", float64(cr)*20)
88				if withinQuota {
89					base += 5
90					add("quota_health", 5)
91				}
92	
93			default:
94				// Treat unspecified as default.
95				if cand.CostClass == "local" {
96					base += 25
97					add("deployment_locality", 25)
98				} else if withinQuota {
99					base += 15
100					add("quota_health", 15)
101				}
102				base -= float64(cr) * 10
103				add("cost", -float64(cr)*10)
104			}
105		}
106	
107		// Provider preference bias.
108		if !hasPowerBounds {
109			switch cand.ProviderPreference {
110			case "local-first", "":
111				if cand.CostClass == "local" {
112					base += 30
113					add("deployment_locality", 30)
114				}
115			case "subscription-first":
116				if cand.IsSubscription && cand.QuotaOK {
117					base += 30
118					add("quota_health", 30)
119				}
120			}
121		}
122	
123		// Quota signals.
124		if cand.IsSubscription {
125			// Stale quota penalty.
126			if cand.QuotaStale {
127				base -= 15
128				add("quota_health", -15)
129			}
130	
131			// Trend-based adjustments.
132			switch cand.QuotaTrend {
133			case "exhausting":
134				base -= 40
135				add("quota_health", -40)
136			case "burning":
137				base -= 20
138				add("quota_health", -20)
139			case "healthy":
140				base += 10
141				add("quota_health", 10)
142			}
143	
144			// Continuous quota pressure: subscription harnesses should start
145			// yielding before they are nearly exhausted, with steeper demotion
146			// once headroom drops below 50% and again below 20%.
147			if cand.QuotaPercentUsed > 0 {
148				penalty := quotaPressurePenalty(cand.QuotaPercentUsed)
149				base -= penalty
150				add("quota_health", -penalty)
151			}
152		}
153	
154		// Historical success-rate adjustment (only when sufficient samples).
155		if cand.HistoricalSuccessRate >= 0 {
156			switch {
157			case cand.HistoricalSuccessRate >= 0.8:
158				base += 20
159				add("quota_health", 20)
160			case cand.HistoricalSuccessRate < 0.5:
161				base -= 30
162				add("quota_health", -30)
163			}
164		}
165		if cand.ProviderSuccessRate >= 0 {
166			switch {
167			case cand.ProviderSuccessRate >= 0.8:
168				base += 25
169				add("quota_health", 25)
170			case cand.ProviderSuccessRate < 0.5:
171				base -= 35
172				add("quota_health", -35)
173			}
174		}
175	
176		// Cooldown demotion: candidate has had recent failures.
177		if cand.InCooldown {
178			base -= 50
179			add("quota_health", -50)
180		}
181	
182		// Sticky affinity is a bonus after eligibility, not a hard pin.
183		if cand.StickyMatch {
184			base += StickyAffinityBonus
185			add("sticky_affinity", StickyAffinityBonus)
186		}
187	
188		// Utilization pressure can outweigh stickiness when the chosen server is
189		// already busy or saturated.
190		// Unknown or stale utilization is treated explicitly. Missing data gets a
191		// small penalty so it cannot outrank a peer with real healthy evidence by
192		// accident.
193		if cand.EndpointSaturated {
194			base -= 300
195			add("utilization", -300)
196		}
197		if cand.EndpointLoad > 0 {
198			loadPenalty := cand.EndpointLoad * 10
199			if cand.EndpointLoadFresh {
200				loadPenalty *= 2
201			} else {
202				loadPenalty += unknownUtilizationPenalty
203			}
204			if loadPenalty > 60 {
205				loadPenalty = 60
206			}
207			base -= loadPenalty
208			add("utilization", -loadPenalty)
209		} else if !cand.EndpointLoadFresh {
210			base -= unknownUtilizationPenalty
211			add("utilization", -unknownUtilizationPenalty)
212		}
213	
214		// Provider affinity: explicit provider pins are filtered before scoring;
215		// this bonus only affects the ordering among still-eligible candidates
216		// that share the pinned provider identity.
217		if cand.ProviderAffinityMatch {
218			base += 15
219			add("deployment_locality", 15)
220		}
221	
222		if cand.Power > 0 && cand.MinPower == 0 && cand.MaxPower == 0 {
223			base += float64(cand.Power) * 12
224			add("power", float64(cand.Power)*12)
225		}
226		if cand.Power > 0 {
227			if cand.MinPower > 0 && cand.Power < cand.MinPower {
228				// Below-min candidates need a materially steeper hit so a free but
229				// underpowered route does not outrank an in-band option purely on cost.
230				penalty := float64(cand.MinPower-cand.Power) * belowMinPowerPenalty
231				base -= penalty
232				add("power", -penalty)
233			}
234			if cand.MaxPower > 0 && cand.Power > cand.MaxPower {
235				penalty := float64(cand.Power - cand.MaxPower)
236				base -= penalty
237				add("power", -penalty)
238			}
239		}
240		if cand.Power > 0 && cand.CostUSDPer1kTokens > 0 {
241			costPenalty := cand.CostUSDPer1kTokens * 500
242			if costPenalty > 60 {
243				costPenalty = 60
244			}
245			base -= costPenalty
246			add("cost", -costPenalty)
247		}
248		if cand.Power > 0 && cand.CostUSDPer1kTokens == 0 && candidateWithinPowerBounds(cand) {
249			switch {
250			case cand.CostClass == "local":
251				base += 15
252				add("cost", 15)
253			case cand.IsSubscription && cand.QuotaOK && !cand.QuotaStale && cand.QuotaPercentUsed < 80:
254				base += 15
255				add("quota_health", 15)
256			}
257		}
258		if cand.Power >= 9 && cand.IsSubscription && candidateWithinPowerBounds(cand) && cand.QuotaOK && !cand.QuotaStale && cand.QuotaPercentUsed < 80 {
259			base += 20
260			add("power", 20)
261		}
262	
263		// Context headroom is a ranking signal for otherwise eligible candidates.
264		// A larger spare window gives the model more room for completion and tool
265		// overhead, so reward it modestly without overpowering the primary policy.
266		if cand.ContextHeadroom > 0 {
267			headroomBonus := float64(cand.ContextHeadroom) / 1000.0
268			if headroomBonus > 30 {
269				headroomBonus = 30
270			}
271			base += headroomBonus
272			add("context_headroom", headroomBonus)
273		}
274	
275		// Observation-derived perf bias.
276		havePerfSignal := false
277		if cand.ObservedTokensPerSec > 0 {
278			// Small additive bonus, scaled.
279			bonus := cand.ObservedTokensPerSec / 100.0
280			base += bonus
281			add("performance", bonus)
282			havePerfSignal = true
283		}
284		if cand.ObservedLatencyMS > 0 {
285			// Latency is a tiebreaker-scale signal: faster endpoints gain a small
286			// bonus while very slow endpoints receive little benefit.
287			bonus := 1000.0 / cand.ObservedLatencyMS
288			base += bonus
289			add("performance", bonus)
290			havePerfSignal = true
291		}
292		if !havePerfSignal {
293			// Missing performance data is deliberate and mildly penalized rather
294			// than treated as a hidden zero-value bonus.
295			base -= unknownPerformancePenalty
296			add("performance", -unknownPerformancePenalty)
297		}
298		if cand.CostClass == "experimental" {
299			base -= 75
300			add("deployment_locality", -75)
301		}
302	
303		// base tracks the implicit profile baseline so the components sum to the
304		// same total as scorePolicy's legacy behavior.
305		components["base"] = base - (components["cost"] + components["deployment_locality"] + components["quota_health"] + components["sticky_affinity"] + components["utilization"] + components["power"] + components["context_headroom"] + components["performance"])
306		return components
307	}
308	
309	func quotaPressurePenalty(percentUsed int) float64 {
310		if percentUsed <= 0 {
311			return 0
312		}
313		penalty := float64(percentUsed) * 0.5
314		if percentUsed > 50 {
315			penalty += float64(percentUsed-50) * 1.5
316		}
317		if percentUsed > 80 {
318			penalty += float64(percentUsed-80) * 3
319		}
320		return penalty
321	}
322	
323	func candidateWithinPowerBounds(cand candidateInternal) bool {
324		if cand.Power <= 0 {
325			return false
326		}
327		if cand.MinPower > 0 && cand.Power < cand.MinPower {
328			return false
329		}
330		if cand.MaxPower > 0 && cand.Power > cand.MaxPower {
331			return false
332		}
333		return true
334	}
