8	func TestScorePowerSelectsPrepaidFrontierWhenQuotaHealthy(t *testing.T) {
9		in := scorePowerInputs()
10	
11		dec, err := Resolve(Request{Policy: "smart"}, in)
12		if err != nil {
13			t.Fatalf("Resolve: %v", err)
14		}
15		if dec.Harness != "codex" || dec.Model != "frontier" {
16			t.Fatalf("winner=%s/%s, want codex/frontier", dec.Harness, dec.Model)
17		}
18		assertCandidatePower(t, dec.Candidates, "codex", "", 10)
19	}
