108	func TestSoftPowerScoring_BelowMinPenaltyIsSteeperPerPoint(t *testing.T) {
109		in := softPowerInputs(map[string]int{
110			"below-min": 7,
111			"above-max": 11,
112		})
113	
114		dec, err := Resolve(Request{MinPower: 8, MaxPower: 10}, in)
115		if err != nil {
116			t.Fatalf("Resolve: %v", err)
117		}
118		var below, above Candidate
119		for _, c := range dec.Candidates {
120			switch c.Provider {
121			case "below-min":
122				below = c
123			case "above-max":
124				above = c
125			}
126		}
127		if below.Provider != "below-min" || above.Provider != "above-max" {
128			t.Fatalf("candidates=%+v, want both power probes", dec.Candidates)
129		}
130		belowPerPoint := -below.ScoreComponents["power"] / float64(8-below.Power)
131		abovePerPoint := -above.ScoreComponents["power"] / float64(above.Power-10)
132		if belowPerPoint <= abovePerPoint {
133			t.Fatalf("below-min penalty per point=%v, want steeper than above-max=%v (below=%#v above=%#v)", belowPerPoint, abovePerPoint, below, above)
134		}
135	}
