184		}
185		return Inputs{
186			Harnesses: []HarnessEntry{{
187				Name:                "fiz",
188				Surface:             "embedded-openai",
189				CostClass:           "medium",
190				AutoRoutingEligible: true,
191				ExactPinSupport:     true,
192				Available:           true,
193				QuotaOK:             true,
194				SubscriptionOK:      true,
195				SupportsTools:       true,
196				Providers:           providers,
197			}},
198			ModelEligibility: testPowerLookup(powers),
199			Now:              time.Date(2026, 4, 30, 0, 0, 0, 0, time.UTC),
