289	func TestScorePowerCostAndSpeedBreakTies(t *testing.T) {
290		t.Run("cost", func(t *testing.T) {
291			in := tieBreakInputs()
292			dec, err := Resolve(Request{MinPower: 7}, in)
293			if err != nil {
