11	func TestRoutingPolicyInvariants(t *testing.T) {
12		cases := []struct {
13			policyStatement string
14			req             Request
15			inputs          Inputs
16			wantHarness     string
17			wantProvider    string
18			wantEndpoint    string
19			wantModel       string
20			wantOnlyHarness string
21			wantErrContains string
22			wantRejected    map[string]FilterReason
23		}{
24			{
25				policyStatement: "config only sets up provider sources; routing uses discovered inventory",
26				req:             Request{Model: "configured-default"},
27				inputs:          policyBaseInputs(),
28				wantErrContains: "no live endpoint offers a match",
29				wantRejected: map[string]FilterReason{
30					"fiz/local": FilterReasonScoredBelowTop,
31					"fiz/paid":  FilterReasonScoredBelowTop,
32					"codex/":    FilterReasonScoredBelowTop,
33				},
34			},
35			{
36				policyStatement: "if no power provider is configured, use the best cheapest viable model",
37				req:             Request{},
38				inputs:          policyInputsWithoutPower(),
39				wantHarness:     "fiz",
40				wantProvider:    "local",
41				wantModel:       "local-good",
42			},
43			{
44				policyStatement: "soft bounded power can still prefer a healthier subscription route",
45				req:             Request{MinPower: 7, MaxPower: 7},
46				inputs:          policyInputsWithDiscoveredLocalDefault(),
47				wantHarness:     "fiz",
48				wantProvider:    "local",
49				wantModel:       "local-good",
50			},
51			{
52				policyStatement: "if local/free is unavailable, fall back to the best viable non-local candidate",
53				req:             Request{MinPower: 7},
54				inputs:          policyInputsWithLocalUnavailable(),
55				wantHarness:     "codex",
56				wantModel:       "cloud-frontier",
57				wantRejected: map[string]FilterReason{
58					"fiz/": FilterReasonUnhealthy,
59				},
60			},
61			{
62				policyStatement: "soft min/max power demotes undershoot without filtering candidates",
63				req:             Request{MinPower: 8, MaxPower: 8},
64				inputs:          policyInputsWithDiscoveredLocalDefault(),
65				wantHarness:     "codex",
66				wantModel:       "cloud-frontier",
67			},
68			{
69				policyStatement: "an exact model pin overrides local preference",
70				req:             Request{Model: "paid-strong"},
71				inputs:          policyInputsWithDiscoveredLocalDefault(),
72				wantHarness:     "fiz",
73				wantProvider:    "paid",
74				wantModel:       "paid-strong",
75				wantRejected: map[string]FilterReason{
76					"fiz/local": FilterReasonScoredBelowTop,
77				},
78			},
79			{
80				policyStatement: "a provider endpoint pin is exclusive",
81				req:             Request{Provider: "paid@secondary", Model: "paid-strong"},
82				inputs:          policyInputsWithProviderEndpoints(),
83				wantHarness:     "fiz",
84				wantProvider:    "paid@secondary",
85				wantEndpoint:    "secondary",
86				wantModel:       "paid-strong",
87				wantRejected: map[string]FilterReason{
88					"fiz/paid@primary": FilterReasonPinMismatch,
89				},
90			},
91			{
92				policyStatement: "a harness pin is exclusive",
93				req:             Request{Harness: "codex", Model: "cloud-frontier"},
94				inputs:          policyBaseInputs(),
95				wantHarness:     "codex",
96				wantModel:       "cloud-frontier",
97				wantOnlyHarness: "codex",
98			},
99			{
100				policyStatement: "unknown-power models remain routable when no power bound is requested",
101				req:             Request{},
102				inputs:          policyInputsWithUnknownPowerModel(),
103				wantHarness:     "fiz",
104				wantProvider:    "local",
105				wantModel:       "local-good",
106			},
107			{
108				policyStatement: "unknown-power exact pins are allowed",
109				req:             Request{Model: "unknown-model"},
110				inputs:          policyInputsWithUnknownPowerModel(),
111				wantHarness:     "fiz",
112				wantProvider:    "unknown",
113				wantModel:       "unknown-model",
114			},
115			{
116				policyStatement: "provider/deployment class keeps local community models below cloud frontier when benchmarks tie",
117				req:             Request{},
118				inputs:          policyInputsWithTiedBenchmarks(),
119				wantHarness:     "codex",
120				wantModel:       "cloud-frontier",
121			},
122		}
123	
124		for _, tc := range cases {
125			t.Run(tc.policyStatement, func(t *testing.T) {
126				dec, err := Resolve(tc.req, tc.inputs)
127				if tc.wantErrContains != "" {
128					if err == nil {
129						t.Fatalf("policy_statement=%q: Resolve succeeded with decision=%#v, want error containing %q", tc.policyStatement, dec, tc.wantErrContains)
130					}
131					if !strings.Contains(err.Error(), tc.wantErrContains) {
132						t.Fatalf("policy_statement=%q: error=%q, want contains %q", tc.policyStatement, err.Error(), tc.wantErrContains)
133					}
134				} else if err != nil {
135					t.Fatalf("policy_statement=%q: Resolve error: %v", tc.policyStatement, err)
136				}
137	
138				if tc.wantHarness != "" && dec.Harness != tc.wantHarness {
139					t.Fatalf("policy_statement=%q: harness=%q, want %q; candidates=%s", tc.policyStatement, dec.Harness, tc.wantHarness, policyCandidateSummary(dec.Candidates))
140				}
141				if tc.wantProvider != "" && dec.Provider != tc.wantProvider {
142					t.Fatalf("policy_statement=%q: provider=%q, want %q; candidates=%s", tc.policyStatement, dec.Provider, tc.wantProvider, policyCandidateSummary(dec.Candidates))
143				}
144				if tc.wantEndpoint != "" && dec.Endpoint != tc.wantEndpoint {
145					t.Fatalf("policy_statement=%q: endpoint=%q, want %q; candidates=%s", tc.policyStatement, dec.Endpoint, tc.wantEndpoint, policyCandidateSummary(dec.Candidates))
146				}
147				if tc.wantModel != "" && dec.Model != tc.wantModel {
148					t.Fatalf("policy_statement=%q: model=%q, want %q; candidates=%s", tc.policyStatement, dec.Model, tc.wantModel, policyCandidateSummary(dec.Candidates))
149				}
150				if tc.wantOnlyHarness != "" {
151					for _, candidate := range dec.Candidates {
152						if candidate.Harness != tc.wantOnlyHarness {
153							t.Fatalf("policy_statement=%q: candidate harness=%q, want only %q; candidates=%s", tc.policyStatement, candidate.Harness, tc.wantOnlyHarness, policyCandidateSummary(dec.Candidates))
154						}
155					}
156				}
157				for key, want := range tc.wantRejected {
158					candidate, ok := policyCandidateByKey(dec.Candidates, key)
159					if !ok {
160						t.Fatalf("policy_statement=%q: candidate %q not found in %s", tc.policyStatement, key, policyCandidateSummary(dec.Candidates))
161					}
162					if candidate.Eligible {
163						t.Fatalf("policy_statement=%q: candidate %q remained eligible, want rejected with %q", tc.policyStatement, key, want)
164					}
165					if candidate.FilterReason != want {
166						t.Fatalf("policy_statement=%q: candidate %q filter_reason=%q, want %q; reason=%q", tc.policyStatement, key, candidate.FilterReason, want, candidate.Reason)
167					}
168				}
169			})
170		}
171	}
