65		if known.ScoreComponents == nil || unknown.ScoreComponents == nil {
66			t.Fatalf("score components must be populated: known=%v unknown=%v", known.ScoreComponents, unknown.ScoreComponents)
67		}
68		for _, key := range []string{"base", "cost", "deployment_locality", "quota_health", "utilization", "performance", "power", "context_headroom", "sticky_affinity"} {
69			if _, ok := known.ScoreComponents[key]; !ok {
70				t.Fatalf("known score components missing %q: %+v", key, known.ScoreComponents)
71			}
72			if _, ok := unknown.ScoreComponents[key]; !ok {
