317		// current score policy, then the locality tiebreak keeps the local route.
318		// default + local-first: fiz (local) = 100+25-0 = 125; claude = 100+15-20 = 95 → fiz wins
319		// default + subscription-first: fiz = 100+25-0 = 125; claude = 100+30+15-20 = 125 → fiz wins on locality
320		req := Request{Policy: "default", ProviderPreference: ProviderPreferenceSubscriptionFirst}
321		dec, err := Resolve(req, in)
