404	// TestNonClaudeSubscriptionQuotaStale verifies that subscription harnesses
405	// without a durable quota cache have QuotaStale=true in the routing inputs,
406	// causing their scores to be penalized.
407	func TestNonClaudeSubscriptionQuotaStale(t *testing.T) {
408		// Simulate what buildRoutingInputs produces for codex (subscription harness
409		// without a durable quota cache): QuotaOK=true (hardcoded), QuotaStale=true
410		// (no durable cache → conservative stale signal), QuotaTrend=Unknown.
411		codexEntry := HarnessEntry{
412			Name:                "codex",
413			Surface:             "codex",
414			CostClass:           "medium",
415			IsSubscription:      true,
416			AutoRoutingEligible: true,
417			Available:           true,
418			QuotaOK:             true, // hardcoded for non-Claude
419			QuotaStale:          true, // no durable cache → stale
420			QuotaTrend:          QuotaTrendUnknown,
421			SubscriptionOK:      true, // eligible when SubscriptionOK=true
422			DefaultModel:        "gpt-5.4",
423			ExactPinSupport:     true,
424			SupportsTools:       true,
425		}
426	
427		in := Inputs{
428			Harnesses: []HarnessEntry{codexEntry},
429			Now:       time.Now(),
430		}
431		req := Request{Policy: "smart", ProviderPreference: ProviderPreferenceLocalFirst}
432		dec, err := Resolve(req, in)
433		if err != nil {
434			t.Fatalf("Resolve: %v", err)
435		}
436	
437		// codex should still be eligible (QuotaOK=true).
438		if !dec.Eligible() {
439			t.Errorf("codex with QuotaOK=true should be eligible, got ineligible")
440		}
441	
442		// Find the codex candidate and verify the score includes the stale penalty.
443		// smart base for codex: 100 + 40 (cr=2) + 5 (quota) - 15 (stale)
444		// - 5 (unknown utilization) - 5 (unknown performance) = 120.
445		var codexScore float64
446		for _, c := range dec.Candidates {
447			if c.Harness == "codex" {
448				codexScore = c.Score
449			}
450		}
451		if codexScore != 120 {
452			t.Errorf("codex stale quota score: got %.1f, want 120.0", codexScore)
453		}
454	}
