672	// === Smell 3: ddx-4817edfd — capability gating ===
673	//
674	// Per-(harness, provider, model) capability gating: context window,
675	// tool support, effort, permissions.
676	func TestSmellCapabilityGating(t *testing.T) {
677		t.Run("context window", func(t *testing.T) {
678			in := newTestRoutingEngine()
679			// MiniMax has no ContextWindow entry; qwen has 256k.
680			// Request a 80k-token prompt — qwen should pass, MiniMax should be neutral
681			// (unknown ctx → not rejected).
682			req := Request{
683				Provider:              "vidar-omlx",
684				Harness:               "fiz",
685				Model:                 "Qwen3.6-35B-A3B-4bit",
686				EstimatedPromptTokens: 80000,
687			}
688			dec, err := Resolve(req, in)
689			if err != nil {
690				t.Fatalf("Resolve: %v", err)
691			}
692			if dec.Model != "Qwen3.6-35B-A3B-4bit" {
693				t.Errorf("got model=%q, want Qwen3.6", dec.Model)
694			}
695	
696			// Now request a 300k-token prompt — qwen (256k) should be rejected.
697			req.EstimatedPromptTokens = 300000
698			dec2, err := Resolve(req, in)
699			if err == nil && dec2.Eligible() {
700				// Find qwen candidate, should be ineligible.
701				for _, c := range dec2.Candidates {
702					if c.Model == "Qwen3.6-35B-A3B-4bit" && c.Eligible {
703						t.Errorf("300k prompt: qwen (256k) should be ineligible")
704					}
705				}
706			}
707		})
708	
709		t.Run("tool support", func(t *testing.T) {
710			in := newTestRoutingEngine()
711			// Mark vidar-omlx provider as tool-incapable.
712			for i, h := range in.Harnesses {
713				if h.Name == "fiz" {
714					for j, p := range h.Providers {
715						if p.Name == "vidar-omlx" {
716							in.Harnesses[i].Providers[j].SupportsTools = false
717						}
718					}
719					// Disable harness-level tool support too so the OR doesn't rescue.
720					in.Harnesses[i].SupportsTools = false
721				}
722			}
723			req := Request{Policy: "cheap", Provider: "vidar-omlx", RequiresTools: true}
724			dec, err := Resolve(req, in)
725			// vidar-omlx must not be eligible.
726			if err == nil {
727				for _, c := range dec.Candidates {
728					if c.Provider == "vidar-omlx" && c.Eligible {
729						t.Errorf("vidar-omlx without tools must be ineligible when RequiresTools=true")
730					}
731				}
732			}
733		})
734	
735		t.Run("reasoning", func(t *testing.T) {
736			// A harness with no SupportedReasoning must reject reasoning=high.
737			in := newTestRoutingEngine()
738			in.Harnesses = append(in.Harnesses, HarnessEntry{
739				Name:                "no-reasoning-harness",
740				Surface:             "test",
741				CostClass:           "medium",
742				AutoRoutingEligible: true,
743				Available:           true,
744				QuotaOK:             true,
745				SubscriptionOK:      true,
746				ExactPinSupport:     true,
747				DefaultModel:        "x",
748			})
749			req := Request{Policy: "default", Reasoning: "high"}
750			dec, err := Resolve(req, in)
751			if err != nil {
752				t.Fatalf("Resolve: %v", err)
753			}
754			for _, c := range dec.Candidates {
755				if c.Harness == "no-reasoning-harness" && c.Eligible {
756					t.Errorf("no-reasoning-harness must be ineligible when Reasoning=high")
757				}
758			}
759		})
760	
761		t.Run("reasoning off imposes no requirement", func(t *testing.T) {
762			cap := Capabilities{}
763			for _, value := range []string{"off", "0", "none", "false"} {
764				if got, _ := CheckGating(cap, Request{Reasoning: value}); got != "" {
765					t.Fatalf("Reasoning=%q should not gate candidate, got %q", value, got)
766				}
767			}
768		})
769	
770		t.Run("extended reasoning requires advertised support", func(t *testing.T) {
771			cap := Capabilities{SupportedReasoning: []string{"low", "medium", "high", "xhigh", "max"}}
772			if got, _ := CheckGating(cap, Request{Reasoning: "x-high"}); got != "" {
773				t.Fatalf("x-high should normalize to advertised xhigh, got %q", got)
774			}
775			if got, _ := CheckGating(Capabilities{SupportedReasoning: []string{"low"}}, Request{Reasoning: "max"}); got == "" {
776				t.Fatal("max should reject candidates that do not advertise it")
777			}
778		})
779	
780		t.Run("numeric reasoning gates against max", func(t *testing.T) {
781			cap := Capabilities{MaxReasoningTokens: 4096}
782			if got, _ := CheckGating(cap, Request{Reasoning: "2048"}); got != "" {
783				t.Fatalf("numeric value under max should pass, got %q", got)
784			}
785			if got, _ := CheckGating(cap, Request{Reasoning: "8192"}); got == "" {
786				t.Fatal("numeric value over max should fail")
787			}
