821	// === Smell 5: single observation store + cooldown abstraction ===
822	//
823	// Cooldown demotion is applied uniformly via Inputs.ProviderCooldowns.
824	// A provider in cooldown loses score; without demotion it would have won.
825	func TestSmellSingleCooldownAbstraction(t *testing.T) {
826		in := newTestRoutingEngine()
827		// Without cooldown: with provider affinity to vidar-omlx, vidar wins.
828		baseReq := Request{Policy: "cheap", Harness: "fiz", Provider: "vidar-omlx", Model: "qwen/qwen3.6"}
829		dec0, err := Resolve(baseReq, in)
830		if err != nil {
831			t.Fatalf("Resolve: %v", err)
832		}
833		if dec0.Provider != "vidar-omlx" {
834			t.Fatalf("baseline: vidar should win with affinity; got %q", dec0.Provider)
835		}
836	
837		// Now put vidar-omlx in cooldown. Other providers are still eligible
838		// (provider pin is soft when paired only with Harness — not a hard reject)
839		// so the cooldown demotion lets a non-cooldowned candidate take over.
840		in.ProviderCooldowns = map[string]time.Time{
841			"vidar-omlx": in.Now.Add(-5 * time.Second),
842		}
843		in.CooldownDuration = 30 * time.Second
844	
845		// Use a cheap-tier request without the hard provider pin so cooldown
846		// demotion is observable.
847		cooldownReq := Request{Policy: "cheap", Harness: "fiz", Model: "qwen/qwen3.6"}
848		dec, err := Resolve(cooldownReq, in)
849		if err != nil {
850			t.Fatalf("Resolve: %v", err)
851		}
852		// Vidar should still resolve but with a -50 cooldown demotion — openrouter
853		// (no cooldown) overtakes via score, even though both share local cost class.
854		if dec.Provider == "vidar-omlx" {
855			t.Errorf("under cooldown vidar-omlx should NOT be top pick; got %q", dec.Provider)
856		}
857	
858		// After cooldown expires (Now > failedAt + cooldown), vidar is no longer demoted.
859		in.Now = in.Now.Add(60 * time.Second)
860		dec2, err := Resolve(cooldownReq, in)
861		if err != nil {
862			t.Fatalf("Resolve after cooldown: %v", err)
863		}
864		// Find both candidates' eligibility/scores.
865		var vidarScore, openrouterScore float64
866		for _, c := range dec2.Candidates {
867			switch c.Provider {
868			case "vidar-omlx":
869				vidarScore = c.Score
870			case "openrouter":
871				openrouterScore = c.Score
872			}
873		}
874		// Confirm cooldown demotion is gone (scores within 1.0 of each other).
875		if vidarScore < openrouterScore-1 {
876			t.Errorf("after cooldown expiry, vidar should not be demoted; vidar=%.1f openrouter=%.1f", vidarScore, openrouterScore)
877		}
878	}
