880	// TestProviderUnreachableHardGatesCandidate verifies that a provider marked
881	// unreachable in Inputs.ProviderUnreachable (within CooldownDuration) is hard-
882	// gated — eligible=false with FilterReasonUnhealthy — instead of merely
883	// demoted in score. This is the FEAT-004 AC-28 path: known-down endpoints are
884	// dispatchability failures. Discovery failures feed this map via
885	// service_routing.providerCooldownsFromSnapshotErrors.
886	func TestProviderUnreachableHardGatesCandidate(t *testing.T) {
887		in := newTestRoutingEngine()
888	
889		// Baseline: vidar-omlx wins with provider affinity.
890		baseReq := Request{Policy: "cheap", Harness: "fiz", Provider: "vidar-omlx", Model: "qwen/qwen3.6"}
891		dec0, err := Resolve(baseReq, in)
892		if err != nil {
893			t.Fatalf("baseline Resolve: %v", err)
894		}
895		if dec0.Provider != "vidar-omlx" {
896			t.Fatalf("baseline: vidar should win with affinity; got %q", dec0.Provider)
897		}
898	
899		// Mark vidar-omlx unreachable. Without an explicit pin, the candidate
900		// should be hard-rejected (not just demoted) with FilterReasonUnhealthy.
901		in.ProviderUnreachable = map[string]time.Time{
902			"vidar-omlx": in.Now.Add(-5 * time.Second),
903		}
904		in.CooldownDuration = 30 * time.Second
905	
906		cooldownReq := Request{Policy: "cheap", Harness: "fiz", Model: "qwen/qwen3.6"}
907		dec, err := Resolve(cooldownReq, in)
908		if err != nil {
909			t.Fatalf("Resolve under unreachable: %v", err)
910		}
911		if dec.Provider == "vidar-omlx" {
912			t.Errorf("unreachable vidar should NOT be top pick; got %q", dec.Provider)
913		}
914	
915		// Find vidar's candidate row and assert it's hard-rejected, not demoted.
916		var vidar *Candidate
917		for i := range dec.Candidates {
918			if dec.Candidates[i].Provider == "vidar-omlx" {
919				vidar = &dec.Candidates[i]
920				break
921			}
922		}
923		if vidar == nil {
924			t.Fatal("vidar-omlx candidate row missing from decision")
925		}
926		if vidar.Eligible {
927			t.Errorf("vidar-omlx should be Eligible=false under ProviderUnreachable; got Eligible=true")
928		}
929		if vidar.FilterReason != FilterReasonUnhealthy {
930			t.Errorf("vidar-omlx FilterReason = %q, want %q", vidar.FilterReason, FilterReasonUnhealthy)
931		}
932		if !strings.Contains(vidar.Reason, "known unreachable") {
933			t.Errorf("vidar-omlx Reason = %q, want it to contain 'known unreachable'", vidar.Reason)
934		}
935	
936		// After cooldown TTL expires, vidar is eligible again.
937		in.Now = in.Now.Add(60 * time.Second)
938		dec2, err := Resolve(baseReq, in)
939		if err != nil {
940			t.Fatalf("Resolve after TTL: %v", err)
941		}
942		if dec2.Provider != "vidar-omlx" {
943			t.Errorf("after TTL expiry with affinity, vidar should win; got %q", dec2.Provider)
944		}
945	}
