1	package routing
2	
3	import (
4		"fmt"
5		"strings"
6	
7		"github.com/easel/fizeau/internal/modelcatalog"
8		"github.com/easel/fizeau/internal/reasoning"
9	)
10	
11	// Capabilities describes what a (harness, provider, model) tuple can do.
12	// Populated from harness config + catalog metadata + provider discovery.
13	type Capabilities struct {
14		ContextWindow      int      // resolved tokens; 0 = unknown
15		SupportsTools      bool     // supports tool/function calling
16		SupportsStreaming  bool     // supports streaming responses
17		SupportedReasoning []string // supported public reasoning values
18		MaxReasoningTokens int      // 0 means numeric reasoning is unsupported/unknown
19		SupportedPerms     []string // {"safe","supervised","unrestricted"} subset
20		ExactPinSupport    bool     // accepts exact concrete model pins
21		SupportedModels    []string // nil = no static allow-list
22	}
23	
24	// HasReasoning returns true if the candidate supports the requested reasoning
25	// value. Empty, auto, off, and numeric 0 impose no requirement.
26	func (c Capabilities) HasReasoning(value string) bool {
27		policy, err := reasoning.ParseString(value)
28		if err != nil {
29			return false
30		}
31		switch policy.Kind {
32		case reasoning.KindUnset, reasoning.KindAuto, reasoning.KindOff:
33			return true
34		case reasoning.KindTokens:
35			return c.MaxReasoningTokens > 0 && policy.Tokens <= c.MaxReasoningTokens
36		case reasoning.KindNamed:
37			for _, supported := range c.SupportedReasoning {
38				normalized, err := reasoning.Normalize(supported)
39				if err == nil && normalized == policy.Value {
40					return true
41				}
42			}
43			return false
44		default:
45			return false
46		}
47	}
48	
49	// HasPermissions returns true if the candidate supports the requested level.
50	// An empty permission level always returns true.
51	func (c Capabilities) HasPermissions(perm string) bool {
52		if perm == "" {
53			return true
54		}
55		for _, p := range c.SupportedPerms {
56			if strings.EqualFold(p, perm) {
57				return true
58			}
59		}
60		return false
61	}
62	
63	// HasModel returns true when the exact model pin is within the static
64	// harness allow-list. A nil allow-list means the harness delegates validation
65	// to provider-side model checks.
66	func (c Capabilities) HasModel(model string) bool {
67		if c.SupportedModels == nil || model == "" {
68			return true
69		}
70		for _, supported := range c.SupportedModels {
71			if supported == model {
72				return true
73			}
74		}
75		return false
76	}
77	
78	// CheckGating applies all capability gates against a request and returns
79	// the first failure reason (free-form string for diagnostics) plus the
80	// typed FilterReason category for the failure. Returns ("", FilterReasonEligible)
81	// when all gates pass.
82	//
83	// The typed return is the authoritative classification — callers must not
84	// re-classify by parsing the string. The string is for human-readable
85	// diagnostics only.
86	//
87	// Fixes ddx-4817edfd subtree: pre-dispatch capability check covering
88	// context window, tool support, effort, permissions.
89	func CheckGating(cap Capabilities, req Request) (string, FilterReason) {
90		// Context window gating: if the request declares prompt size or an effort
91		// that implies a minimum context, reject candidates that can't fit.
92		minCtx := req.MinContextWindow()
93		if minCtx > 0 {
94			if cap.ContextWindow <= 0 {
95				return fmt.Sprintf("context window unknown < required %d", minCtx), FilterReasonContextTooSmall
96			}
97			if cap.ContextWindow < minCtx {
98				return fmt.Sprintf("context window %d < required %d", cap.ContextWindow, minCtx), FilterReasonContextTooSmall
99			}
100		}
101	
102		// Tool-calling support gating.
103		if req.RequiresTools && !cap.SupportsTools {
104			return "tool calling not supported", FilterReasonNoToolSupport
105		}
106	
107		if !cap.HasReasoning(req.Reasoning) {
108			return fmt.Sprintf("reasoning %q not supported", req.Reasoning), FilterReasonReasoningUnsupported
109		}
110	
111		// Permissions support gating.
112		if !cap.HasPermissions(req.Permissions) {
113			return fmt.Sprintf("permissions %q not supported", req.Permissions), FilterReasonScoredBelowTop
114		}
115	
116		if req.Model != "" && !cap.HasModel(req.Model) {
117			return "model not in harness allow-list", FilterReasonScoredBelowTop
118		}
119	
120		// Exact-pin gating: an explicit Model field requires ExactPinSupport.
121		if req.Model != "" && !cap.ExactPinSupport {
122			return "exact model pin not supported", FilterReasonScoredBelowTop
123		}
124	
125		return "", FilterReasonEligible
126	}
127	
128	// CheckPowerEligibility applies catalog-power gates for unpinned automatic
129	// routing. Any explicit hard route pin (harness, provider, or model) bypasses
130	// this gate so caller-chosen routes are never broadened or overridden by
131	// power policy.
132	func CheckPowerEligibility(lookup func(string) (ModelEligibility, bool), model string, req Request) (string, FilterReason) {
133		if req.Model != "" || req.Provider != "" || req.Harness != "" || lookup == nil {
134			return "", FilterReasonEligible
135		}
136		if model == "" {
137			return "model has no catalog power metadata", FilterReasonPowerMissing
138		}
139		eligibility, ok := lookup(model)
140		if !ok {
141			if req.MinPower > 0 || req.MaxPower > 0 {
142				return fmt.Sprintf("model %q has no catalog power metadata", model), FilterReasonPowerMissing
143			}
144			return "", FilterReasonEligible
145		}
146		if eligibility.ExactPinOnly {
147			return fmt.Sprintf("model %q is exact-pin-only", model), FilterReasonExactPinOnly
148		}
149		if !eligibility.AutoRoutable {
150			if eligibility.Power <= 0 {
151				return fmt.Sprintf("model %q has no catalog power metadata", model), FilterReasonPowerMissing
152			}
153			return fmt.Sprintf("model %q is not auto-routable", model), FilterReasonNotAutoRoutable
154		}
155		return "", FilterReasonEligible
156	}
