158	// CheckProviderDefaultEligibility returns a rejection reason when the provider
159	// entry has ExcludeFromDefaultRouting=true and the request does not carry an
160	// explicit provider, harness, or exact model pin. Any explicit hard pin
161	// bypasses this gate so the operator can still reach opt-out providers
162	// intentionally.
163	func CheckProviderDefaultEligibility(providerName string, actualCashSpend bool, billing modelcatalog.BillingModel, excluded bool, req Request) (string, FilterReason) {
164		if !excluded {
165			return "", FilterReasonEligible
166		}
167		if req.Provider != "" || req.Harness != "" || req.Model != "" {
168			return "", FilterReasonEligible
169		}
170		if actualCashSpend || billing == modelcatalog.BillingModelPerToken {
171			return fmt.Sprintf("pay-per-token provider %s requires metered opt-in for unpinned automatic routing", providerName), FilterReasonMeteredOptInRequired
172		}
173		return fmt.Sprintf("provider %s excluded from default routing (include_by_default=false)", providerName), FilterReasonProviderExcludedFromDefault
174	}
