176	// resolveRequestReasoning returns a copy of req with Reasoning resolved to the
177	// catalog's reasoning default for the request's policy/surface
178	// when the request asks for Reasoning=auto. This must run before CheckGating
179	// so candidates that only support a different reasoning level (e.g. an
180	// off-only variant under a policy whose surface default is "high") are
181	// correctly disqualified by the capability gate. Other Reasoning values
182	// (unset, off, named, numeric) are left untouched, preserving the existing
183	// behavior of those code paths.
184	func resolveRequestReasoning(req Request, surface string, resolver func(policy, surface string) (string, bool)) Request {
185		if resolver == nil || req.Policy == "" {
186			return req
187		}
188		policy, err := reasoning.ParseString(req.Reasoning)
189		if err != nil || policy.Kind != reasoning.KindAuto {
190			return req
191		}
192		resolved, ok := resolver(req.Policy, surface)
193		if !ok || resolved == "" {
194			return req
195		}
196		out := req
197		out.Reasoning = resolved
198		return out
199	}
